import numpy as np

class Variable:
    """Represents a variable in the autodiff graph."""

    def __init__(self, value):
        self.value = value
        self.grad = None

    def backward(self):
        """Backpropagates the gradient through this variable."""
        if self.grad is not None:
            self.value.backward(self.grad)
        return self

    def backward_value(self):
        """Returns the backwarded value of this variable."""
        return self.value.backward(self.grad)

class Function:
    """Represents a mathematical function."""

    def __init__(self, func):
        self.func = func
        self.input_vars = []
        self.output_vars = []

