```java
import java.util.HashMap;
import java.util.Map;

public class IndexCache {
    private Map<String, Map<String, Object>> cache = new HashMap<>();

    public void put(String indexFile, String key, Object value) {
        if (!cache.containsKey(indexFile)) {
            cache.put(indexFile, new HashMap<>());
        }
        cache.get(indexFile).put(key, value);
    }

    public Object get(String indexFile, String key) {
        if (cache.containsKey(indexFile)) {
            return cache.get(indexFile).get(key);
        }
        return null;
    }

    public void remove(String indexFile, String key) {
        if (cache.containsKey(indexFile)) {
            cache.get(indexFile).remove(key);
            if (cache.get(indexFile).isEmpty()) {
                cache.remove(indexFile);
            }
        }
    }
}
